  const [watchlistLoading, setWatchlistLoading] = useState(false);
  const [watchlist, setWatchlist] = useState([]);

  // Load watchlist from localStorage on mount
  useEffect(() => {
    const savedWatchlist = JSON.parse(localStorage.getItem("watchlist")) || [];
    setWatchlist(savedWatchlist);
  }, []);

  // Check if a movie is in the watchlist
  const isInWatchlist = (movieId) => {
    return watchlist.some((item) => item.id === movieId);
  };

  const handleWatchlistClick = (movie) => {
  setWatchlistLoading(true); // start loading

  try {
    const existing = JSON.parse(localStorage.getItem("watchlist")) || [];
    const alreadyAdded = existing.find((item) => item.id === movie.id);

    let message = "";

    if (!alreadyAdded) {
      const updated = [...existing, movie];
      localStorage.setItem("watchlist", JSON.stringify(updated));
      message = `${movie.title} has been added successfully`;
    } else {
      const updated = existing.filter((item) => item.id !== movie.id);
      localStorage.setItem("watchlist", JSON.stringify(updated));
      message = `${movie.title} has been removed from your watchlist`;
    }

    // small delay for UX
    setTimeout(() => {
      setWatchlistLoading(false);
      alert(message);
    }, 300);

  } catch (err) {
    console.error("Failed to update watchlist", err);
    setWatchlistLoading(false);
  }
};

